Implementasi Observer Pattern yang robust harus memperhatikan *thread safety* dan *error handling*. Satu observer yang error tidak boleh menjatuhkan seluruh sistem notifikasi.

Berikut implementasi menggunakan `threading.Lock` untuk konkurensi dan `abc` untuk enforce interface.

```python
from abc import ABC, abstractmethod
from typing import List
import threading
import logging

# Konfigurasi Logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("ShiroAI_Observer")

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject(ABC):
    @abstractmethod
    def attach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def detach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def notify(self) -> None:
        pass

class ConcreteSubject(Subject):
    def __init__(self):
        self._observers: List[Observer] = []
        self._lock = threading.Lock()
        self._state = None

    def attach(self, observer: Observer) -> None:
        with self._lock:
            if observer not in self._observers:
                self._observers.append(observer)
                logger.info("Observer attached successfully.")

    def detach(self, observer: Observer) -> None:
        with self._lock:
            if observer in self._observers:
                self._observers.remove(observer)
                logger.info("Observer detached successfully.")

    def set_state(self, state: any) -> None:
        self._state = state
        self.notify()

    def notify(self) -> None:
        # Copy list untuk menghindari race condition saat iterasi
        with self._lock:
            observers_snapshot = list(self._observers)

        for observer in observers_snapshot:
            try:
                observer.update(self)
            except Exception as e:
                # Isolasi error: Observer yang crash tidak boleh menghentikan notifikasi ke lain
                logger.error(f"Observer failed: {e}", exc_info=True)

class ConcreteObserver(Observer):
    def __init__(self, name: str):
        self.name = name

    def update(self, subject: ConcreteSubject) -> None:
        logger.info(f"[{self.name}] Received update. State: {subject._state}")

# --- Usage Example ---
if __name__ == "__main__":
    subject = ConcreteSubject()
    obs1 = ConcreteObserver("SecurityMonitor")
    obs2 = ConcreteObserver("LogAggregator")

    subject.attach(obs1)
    subject.attach(obs2)

    # Trigger update
    subject.set_state("ALERT: Suspicious Activity Detected")

    # Cleanup
    subject.detach(obs2)
    subject.set_state("INFO: System Normal")
```

### Catatan Keamanan & Performa:
1.  **Thread Safety**: Menggunakan `threading.Lock` wajib jika subjek diakses dari banyak thread. Race condition pada list observer bisa menyebabkan `RuntimeError` atau data leak.
2.  **Exception Isolation**: Blok `try-except` di dalam `notify` krusial. Jika satu observer gagal (misal karena timeout network atau bug internal), observer lain tetap harus menerima notifikasi.
3.  **Memory Leak**: Pastikan observer yang tidak lagi digunakan di-`detach` atau menggunakan *weak reference* jika observer memiliki lifecycle lebih pendek dari subject.
4.  **Validasi Input**: Jika `set_state` menerima input dari user, validasi sebelum `notify` untuk mencegah propagasi data berbahaya (XSS/Injection) ke observer yang mungkin melakukan logging atau rendering.

Jangan pernah gunakan `eval()` langsung pada input user. Itu adalah celah keamanan kritis (Remote Code Execution/RCE). Penyerang dapat menyuntikkan kode Python arbitrer, misalnya `__import__('os').system('rm -rf /')`.

Gunakan modul `ast` (Abstract Syntax Trees) untuk memparse dan memvalidasi ekspresi sebelum evaluasi. Berikut implementasi aman tanpa dependensi eksternal:

```python
import ast
import operator

# Whitelist operator yang diizinkan
ALLOWED_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Pow: operator.pow,
    ast.Mod: operator.mod,
    ast.USub: operator.neg,
    ast.UAdd: operator.pos,
}

class SafeMathVisitor(ast.NodeVisitor):
    def visit_BinOp(self, node):
        if type(node.op) not in ALLOWED_OPERATORS:
            raise ValueError(f"Operator tidak diizinkan: {type(node.op).__name__}")
        left = self.visit(node.left)
        right = self.visit(node.right)
        return ALLOWED_OPERATORS[type(node.op)](left, right)

    def visit_UnaryOp(self, node):
        if type(node.op) not in ALLOWED_OPERATORS:
            raise ValueError(f"Operator unary tidak diizinkan: {type(node.op).__name__}")
        operand = self.visit(node.operand)
        return ALLOWED_OPERATORS[type(node.op)](operand)

    def visit_Num(self, node): # Python < 3.8
        return node.n

    def visit_Constant(self, node): # Python >= 3.8
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Hanya angka yang diizinkan")

    def visit_Expression(self, node):
        return self.visit(node.body)

    def generic_visit(self, node):
        # Blokir semua node lain (fungsi, variabel, import, dll)
        raise ValueError(f"Node tidak diizinkan: {type(node).__name__}")

def safe_math_eval(expression: str) -> float:
    try:
        tree = ast.parse(expression, mode='eval')
        visitor = SafeMathVisitor()
        return visitor.visit(tree)
    except Exception as e:
        raise ValueError(f"Invalid expression: {e}")

# Contoh Penggunaan
if __name__ == "__main__":
    print(safe_math_eval("2 + 3 * 4"))      # Output: 14
    print(safe_math_eval("10 ** 2"))        # Output: 100
    # print(safe_math_eval("__import__('os')")) # Akan raise ValueError
```

### Analisis Keamanan:
1.  **Whitelisting Node:** Hanya node matematika (`BinOp`, `UnaryOp`, `Constant`) yang diizinkan. Semua node lain (seperti `Call`, `Name`, `Import`) diblokir oleh `generic_visit`.
2.  **Mitigasi RCE:** Kode ini mencegah eksekusi fungsi sistem atau akses modul karena parser tidak akan mengeksekusi node fungsi.
3.  **Type Checking:** Hanya angka (`int`, `float`) yang diproses, mencegah injeksi string atau objek lain.

Gunakan metode ini untuk semua kalkulasi berbasis input user di produksi.

Berikut implementasi efisien untuk membandingkan dua dictionary secara rekursif. Fungsi ini mengembalikan struktur perubahan (`added`, `removed`, `changed`) untuk audit konfigurasi atau validasi state.

```python
from typing import Any, Dict, Tuple, List, Union

def diff_dict(dict1: Dict[str, Any], dict2: Dict[str, Any], path: str = "") -> Dict[str, Any]:
    """
    Membandingkan dua dictionary secara rekursif.
    Returns: Dictionary berisi 'added', 'removed', dan 'changed'.
    """
    diff = {
        "added": {},
        "removed": {},
        "changed": {}
    }

    keys1 = set(dict1.keys())
    keys2 = set(dict2.keys())

    # Kunci yang ada di dict2 tapi tidak di dict1 (Added)
    for key in keys2 - keys1:
        diff["added"][key] = dict2[key]

    # Kunci yang ada di dict1 tapi tidak di dict2 (Removed)
    for key in keys1 - keys2:
        diff["removed"][key] = dict1[key]

    # Kunci yang ada di keduanya (Check Changed or Nested)
    for key in keys1 & keys2:
        val1 = dict1[key]
        val2 = dict2[key]

        if isinstance(val1, dict) and isinstance(val2, dict):
            # Rekursif untuk nested dictionary
            nested_diff = diff_dict(val1, val2, path=f"{path}.{key}")

            if any(nested_diff.values()):
                diff["changed"][key] = nested_diff
        elif val1 != val2:
            # Value berbeda
            diff["changed"][key] = {"old": val1, "new": val2}

    return diff

# Contoh Penggunaan
if __name__ == "__main__":
    config_lama = {
        "db": {"host": "localhost", "port": 3306},
        "debug": True
    }

    config_baru = {
        "db": {"host": "192.168.1.10", "port": 3306, "ssl": True},
        "cache": {"enabled": True}
    }

    import json
    result = diff_dict(config_lama, config_baru)
    print(json.dumps(result, indent=2))
```

### Catatan Teknis:
1.  **Kompleksitas:** O(N) di mana N adalah total kunci unik di kedua dictionary.
2.  **Keamanan:** Tidak menggunakan `eval` atau eksekusi dinamis. Aman untuk membandingkan konfigurasi sensitif.
3.  **Recursion Limit:** Python memiliki batas rekursi default (biasanya 1000). Jika struktur dictionary terlalu dalam, pertimbangkan pendekatan iteratif atau naikkan limit dengan `sys.setrecursionlimit` (hati-hati terhadap stack overflow).
4.  **Tipe Data:** Fungsi ini secara spesifik menangani `dict`. Untuk perbandingan list, diperlukan logika tambahan karena urutan (order) mungkin relevan tergantung use case.

Gunakan ini untuk validasi konfigurasi server, audit perubahan setting, atau testing state aplikasi.
